const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const componentBaseFor = (items: Item[]): number => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      counts[item.type] = (counts[item.type] ?? 0) + 1;
    }
  }
  let total = 0;
  for (const type of Object.keys(counts)) {
    const count = counts[type];
    const blocks = Math.floor(count / BLOCK_SIZE);
    const remainder = count % BLOCK_SIZE;
    // Block only applies for exactly 3; if exactly 3, use block premium; otherwise no block discount
    if (count === BLOCK_SIZE) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * BASE_PREMIUMS[type];
    }
    void blocks;
    void remainder;
  }
  return total;
};

const quotePremium = (step: QuoteStep): number => {
  const mainItems = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
  const componentItems = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
  const mainBase = sum(mainItems.map((i) => BASE_PREMIUMS[i.type]));
  const componentBase = componentBaseFor(componentItems);
  const policyBase = mainBase + componentBase;
  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(policyBase + firstInsuranceSurcharge + PROCESSING_FEE);
};

