import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === Empty / trivial cases ===
  it("empty item list → premium 5 G (processing fee only)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(out).toEqual({ results: [{ premium: 5 }] });
  });

  // === Base item premiums (single item, no modifiers, newcomer, first item) ===
  it("single plain sword for newcomer → 100 + 10 first + 5 fee = 115 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it("single plain amulet for newcomer → 60 + 6 first + 5 fee = 71 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(out).toEqual({ results: [{ premium: 71 }] });
  });
  it("single plain staff for newcomer → 80 + 8 first + 5 fee = 93 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(out).toEqual({ results: [{ premium: 93 }] });
  });
  it("single plain potion for newcomer → 40 + 4 first + 5 fee = 49 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(out).toEqual({ results: [{ premium: 49 }] });
  });

  // === Components (runes / moonstones) ===
  it("single rune for newcomer → 25 + 2.5 first + 5 fee = rounded 33 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(out).toEqual({ results: [{ premium: 33 }] });
  });
  it("2 runes → base 50 G (no block)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    // 2 × 25 = 50 base + 5 first-insurance (10%) = 55 + 5 fee = 60
    expect(out).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → base 60 G (block discount applies)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    // 60 base + 6 first-insurance (10%) = 66 + 5 fee = 71
    expect(out).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
  it.todo("7 runes → base 175 G (no extra block)");

  // === Alike components ===
  it.todo("2 runes + 1 moonstone → base 75 G (different types, no block)");
  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");

  // === Cursed surcharge ===
  it.todo("cursed sword (steel, enchantment 3) for newcomer → 165 G (integration example)");

  // === High enchantment surcharge ===
  it.todo("sword enchantment 5 → high-enchantment surcharge applies (newcomer first contract)");
  it.todo("sword enchantment 4 → no high-enchantment surcharge");

  // === Loyalty discount ===
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("customer with 1 year → no loyalty discount");

  // === Follow-up contract discount ===
  it.todo("second quote in scenario receives 15 % follow-up discount");

  // === Modifier scope on multi-item policies ===
  it.todo("cursed sword + plain amulet → 210 G before further modifiers and fee (item-scoped curse)");

  // === Integration: long-standing customer's second contract ===
  it.todo("3-yr customer's 2nd contract, cursed sword enchantment 7 → 160 G");

  // === Rounding ===
  it.todo("premium that yields 197.5 G → rounded up to 198 G");
  it.todo("payout that yields 350.5 G → rounded down to 350 G");

  // === Claim: standard reimbursement ===
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
  it.todo("damage to rune (no enchantment, no material), damage 200 G → payout 100 G");

  // === Claim: high-enchantment clause ===
  it.todo("dragon sword ench 8, damage 1000 G → payout 400 G");
  it.todo("dragon sword ench 9, damage 1000 G → payout 400 G (50 % then deductible)");

  // === Claim: dragon material clause ===
  it.todo("dragon sword ench 5, damage 800 G → payout 700 G (only dragon clause)");

  // === Claim: high-enchantment alone ===
  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (50 % then deductible)");

  // === Claim: deductible per damage event ===
  it.todo("dragon attack on sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // === Multiple items of the same type ===
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two sword damages on a two-sword policy → each damage gets own deductible");
  it.todo("more damage entries than insured items of that type → rejected (throws)");

  // === Cap exhaustion ===
  it.todo("cursed sword cap = 2000 G (cap based on unmodified insurance value)");
  it.todo("sword + 3 runes → insurance sum 1750 G (block does not affect insurance sum)");
  it.todo("two successive 1500 G claims on sword: first 1400 G remaining 600, second 600 remaining 0");

  // === Edge cases ===
  it.todo("unknown item type in quote → throws / non-zero exit");
  it.todo("claim with damage to item not in policy → throws / non-zero exit");
  it.todo("claim with negative damage amount → throws / non-zero exit");
});

