    // 4 × 25 = 100 base + 10 first-insurance (10%) = 110 + 5 fee = 115
    expect(out).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes → base 175 G (no extra block)", () => {
    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
