    expect(out).toEqual({ results: [{ premium: 198 }] });
  });

  // === Alike components ===
  it("2 runes + 1 moonstone → base 75 G (different types, no block)", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
