const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string; cursed?: boolean; enchantment?: number };
type QuoteStep = { op: "quote"; items: Array<Item> };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Array<QuoteStep> };

const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;

const subtotalForType = (type: string, count: number): number =>
  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];

const policyBaseFor = (items: Item[]): number =>
  sum(Object.entries(countByType(items)).map(([type, count]) => subtotalForType(type, count)));

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const surchargeRate = (item: Item): number =>
  (item.cursed ? CURSED_SURCHARGE_RATE : 0) +
  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);

const itemSurcharge = (item: Item): number => BASE_PREMIUMS[item.type] * surchargeRate(item);

const quotePremium = (step: QuoteStep): number => {
  const policyBase = policyBaseFor(step.items);
  const itemSurchargesTotal = sum(step.items.map(itemSurcharge));
  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(policyBase + itemSurchargesTotal + firstInsuranceSurcharge + PROCESSING_FEE);
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

