41	  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
42	
43	const policyBaseFor = (items: Item[]): number =>
44	  sum(Object.entries(countByType(items)).map(([type, count]) => subtotalForType(type, count)));
45	
46	const isHighlyEnchanted = (item: Item): boolean =>
47	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
48	
