  it("premium that yields 197.5 G → rounded up to 198 G", () => {
    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items }],
    });
    // 7 × 25 = 175 base + 17.5 first ins + 5 fee = 197.5 → rounded up to 198
    expect(out).toEqual({ results: [{ premium: 198 }] });
  });
  it("payout that yields 350.5 G → rounded down to 350 G", () => {
    const out = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", enchantment: 8 }] },
        { op: "claim", policy: 0, incident: { cause: "test", damages: [{ itemType: "sword", amount: 901 }] } },
      ],
    });
    // high ench → 50% of 901 = 450.5; − 100 deductible = 350.5 → floor 350
    expect(out.results[1]).toEqual({ payout: 350, remainingCap: 1650 });
  });

  // === Claim: standard reimbursement ===
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
  it.todo("damage to rune (no enchantment, no material), damage 200 G → payout 100 G");

  // === Claim: high-enchantment clause ===
  it.todo("dragon sword ench 8, damage 1000 G → payout 400 G");
  it.todo("dragon sword ench 9, damage 1000 G → payout 400 G (50 % then deductible)");

  // === Claim: dragon material clause ===
  it.todo("dragon sword ench 5, damage 800 G → payout 700 G (only dragon clause)");

  // === Claim: high-enchantment alone ===
  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (50 % then deductible)");

  // === Claim: deductible per damage event ===
  it.todo("dragon attack on sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // === Multiple items of the same type ===
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two sword damages on a two-sword policy → each damage gets own deductible");
  it.todo("more damage entries than insured items of that type → rejected (throws)");

  // === Cap exhaustion ===
  it.todo("cursed sword cap = 2000 G (cap based on unmodified insurance value)");
  it.todo("sword + 3 runes → insurance sum 1750 G (block does not affect insurance sum)");
  it.todo("two successive 1500 G claims on sword: first 1400 G remaining 600, second 600 remaining 0");

  // === Edge cases ===
  it.todo("unknown item type in quote → throws / non-zero exit");
  it.todo("claim with damage to item not in policy → throws / non-zero exit");
  it.todo("claim with negative damage amount → throws / non-zero exit");
});

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string; cursed?: boolean; enchantment?: number };
type QuoteStep = { op: "quote"; items: Array<Item> };
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: Array<QuoteStep> };

const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);

const countByType = (items: Item[]): Record<string, number> => {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
};

const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;

const subtotalForType = (type: string, count: number): number =>
  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];

const policyBaseFor = (items: Item[]): number =>
  sum(Object.entries(countByType(items)).map(([type, count]) => subtotalForType(type, count)));

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const surchargeRate = (item: Item): number =>
  (item.cursed ? CURSED_SURCHARGE_RATE : 0) +
  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);

const itemSurcharge = (item: Item): number => BASE_PREMIUMS[item.type] * surchargeRate(item);

const itemSurchargesFor = (items: Item[]): number => sum(items.map(itemSurcharge));

const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const loyaltyDiscountFor = (policyBase: number, customer: Customer): number =>
  qualifiesForLoyaltyDiscount(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;

const firstInsuranceSurchargeFor = (policyBase: number): number =>
  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;

const isFollowUpQuote = (quoteIndex: number): boolean => quoteIndex > 0;

const followUpDiscountFor = (policyBase: number, quoteIndex: number): number =>
  isFollowUpQuote(quoteIndex) ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;

const quotePremium = ({ items }: QuoteStep, customer: Customer, quoteIndex: number): number => {
  const policyBase = policyBaseFor(items);
  const itemSurchargesTotal = itemSurchargesFor(items);
  const firstInsuranceSurcharge = firstInsuranceSurchargeFor(policyBase);
  const loyaltyDiscount = loyaltyDiscountFor(policyBase, customer);
  const followUpDiscount = followUpDiscountFor(policyBase, quoteIndex);
  return Math.ceil(policyBase + itemSurchargesTotal + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step, quoteIndex) => ({
    premium: quotePremium(step, scenario.customer, quoteIndex),
  }));
  return { results };
};

