const processClaim = (step: ClaimStep, policies: Policy[]): { payout: number; remainingCap: number } => {
  const policy = policies[step.policy];
  const payout = sum(step.incident.damages.map((d) => payoutForDamage(d, policy)));
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const policies: Policy[] = [];
  let quoteIndex = 0;
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const premium = quotePremium(step, scenario.customer, quoteIndex);
      quoteIndex += 1;
      policies.push({ items: step.items, remainingCap: insuranceSumFor(step.items) * CAP_MULTIPLIER });
      return { premium };
    }
    return processClaim(step, policies);
  });
  return { results };
};

